'use client';

import { useState } from 'react';
import { Search, MapPin, Star, Filter, Heart } from 'lucide-react';
import { useRouter } from 'next/navigation';

export default function WorkerMarketplace() {
    const router = useRouter();
    const [searchQuery, setSearchQuery] = useState('');

    const workers = [
        {
            id: 1,
            name: "Mario Sterling",
            profession: "Master Plumber",
            rating: 4.9,
            reviews: 124,
            rate: "$85/hr",
            image: "https://ui-avatars.com/api/?name=Mario+S&background=0D8ABC&color=fff",
            badged: true,
            location: "San Francisco, CA"
        },
        {
            id: 2,
            name: "Sarah Jenkins",
            profession: "Interior Designer",
            rating: 5.0,
            reviews: 89,
            rate: "$120/hr",
            image: "https://ui-avatars.com/api/?name=Sarah+J&background=10B981&color=fff",
            badged: false,
            location: "Oakland, CA"
        },
        {
            id: 3,
            name: "David Chen",
            profession: "Electrician",
            rating: 4.8,
            reviews: 215,
            rate: "$95/hr",
            image: "https://ui-avatars.com/api/?name=David+C&background=F59E0B&color=fff",
            badged: true,
            location: "San Jose, CA"
        }
    ];

    return (
        <div className="min-h-screen bg-slate-50 text-slate-900 pb-24">
            {/* Header */}
            <header className="bg-white/80 backdrop-blur-md sticky top-0 z-10 px-6 py-4 border-b border-slate-100">
                <h1 className="text-2xl font-black mb-1">Find Pros</h1>
                <p className="text-sm text-slate-500 font-medium">Discover top-rated workers near you</p>
            </header>

            {/* Search & Filter */}
            <div className="px-6 py-4">
                <div className="flex gap-3 mb-4">
                    <div className="relative flex-1">
                        <Search className="absolute left-4 top-3.5 w-5 h-5 text-slate-400" />
                        <input
                            type="text"
                            placeholder="Search by name or skill..."
                            className="w-full h-12 pl-12 pr-4 bg-white border border-slate-200 rounded-2xl focus:outline-none focus:border-blue-500 focus:ring-4 focus:ring-blue-500/10 transition-all font-medium placeholder:text-slate-400"
                            value={searchQuery}
                            onChange={(e) => setSearchQuery(e.target.value)}
                        />
                    </div>
                    <button className="w-12 h-12 bg-white border border-slate-200 rounded-2xl flex items-center justify-center text-slate-600 hover:border-slate-300 hover:text-slate-900 transition-colors">
                        <Filter className="w-5 h-5" />
                    </button>
                </div>

                <div className="flex gap-2 overflow-x-auto no-scrollbar pb-2">
                    {['All', 'Plumbers', 'Electricians', 'Cleaners', 'Painters'].map((cat, i) => (
                        <button
                            key={cat}
                            className={`px-4 py-2 rounded-xl text-xs font-bold whitespace-nowrap border transition-all ${i === 0 ? 'bg-slate-900 text-white border-slate-900' : 'bg-white border-slate-200 text-slate-600 hover:border-slate-300'}`}
                        >
                            {cat}
                        </button>
                    ))}
                </div>
            </div>

            {/* Worker List */}
            <div className="px-6 space-y-4">
                {workers.map(worker => (
                    <div
                        key={worker.id}
                        onClick={() => router.push(`/workers/${worker.id}`)}
                        className="bg-white p-4 rounded-3xl border border-slate-100 shadow-sm hover:shadow-md transition-all cursor-pointer group"
                    >
                        <div className="flex gap-4">
                            <div className="relative">
                                <img src={worker.image} className="w-16 h-16 rounded-2xl object-cover shadow-sm" alt={worker.name} />
                                {worker.badged && (
                                    <div className="absolute -bottom-2 -right-2 bg-blue-600 text-white p-1 rounded-full border-2 border-white">
                                        <svg className="w-3 h-3" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" />
                                        </svg>
                                    </div>
                                )}
                            </div>
                            <div className="flex-1 min-w-0">
                                <div className="flex justify-between items-start">
                                    <div>
                                        <h3 className="font-bold text-lg text-slate-900 leading-tight group-hover:text-blue-600 transition-colors">{worker.name}</h3>
                                        <p className="text-slate-500 text-sm font-medium">{worker.profession}</p>
                                    </div>
                                    <div className="flex items-center gap-1 bg-amber-50 px-2 py-1 rounded-lg">
                                        <Star className="w-3.5 h-3.5 text-amber-500 fill-amber-500" />
                                        <span className="text-xs font-bold text-amber-700">{worker.rating}</span>
                                    </div>
                                </div>

                                <div className="mt-3 flex items-center justify-between">
                                    <div className="flex items-center gap-1 text-slate-400 text-xs font-medium">
                                        <MapPin className="w-3.5 h-3.5" />
                                        {worker.location}
                                    </div>
                                    <div className="flex items-center gap-3">
                                        <span className="text-sm font-bold text-slate-900">{worker.rate}</span>
                                    </div>
                                </div>
                            </div>
                        </div>
                    </div>
                ))}
            </div>
        </div>
    );
}
